sql:
SELECT SUM(download_count) AS total_downloads, SUM(citation_count) AS total_citations
FROM document_usage
WHERE doc_id = 0;

SELECT doc_id, SUM(view_count) AS total_views
FROM document_usage
GROUP BY doc_id;

SELECT view_count
FROM document_usage
ORDER BY view_count DESC;

